import{_ as a,p as s,q as n,a1 as e}from"./framework-5866ffd3.js";const t={},p=e(`<h1 id="blkid" tabindex="-1"><a class="header-anchor" href="#blkid" aria-hidden="true">#</a> blkid</h1><p>查看块设备的文件系统类型、LABEL、UUID等信息</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p>在Linux下可以使用 <strong>blkid命令</strong> 对查询设备上所采用文件系统类型进行查询。blkid主要用来对系统的块设备（包括交换分区）所使用的文件系统类型、LABEL、UUID等信息进行查询。要使用这个命令必须安装e2fsprogs软件包。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>blkid <span class="token parameter variable">-L</span> <span class="token operator">|</span> <span class="token parameter variable">-U</span>
blkid <span class="token punctuation">[</span>-c <span class="token punctuation">]</span> <span class="token punctuation">[</span>-ghlLv<span class="token punctuation">]</span> <span class="token punctuation">[</span>-o<span class="token punctuation">]</span> <span class="token punctuation">[</span>-s <span class="token punctuation">]</span><span class="token punctuation">[</span>-t <span class="token punctuation">]</span> -<span class="token punctuation">[</span>w <span class="token punctuation">]</span> <span class="token punctuation">[</span> <span class="token punctuation">..</span>.<span class="token punctuation">]</span>
blkid <span class="token parameter variable">-p</span> <span class="token punctuation">[</span>-s <span class="token punctuation">]</span> <span class="token punctuation">[</span>-O <span class="token punctuation">]</span> <span class="token punctuation">[</span>-S <span class="token punctuation">]</span><span class="token punctuation">[</span>-o<span class="token punctuation">]</span> <span class="token punctuation">..</span>.
blkid <span class="token parameter variable">-i</span> <span class="token punctuation">[</span>-s <span class="token punctuation">]</span> <span class="token punctuation">[</span>-o<span class="token punctuation">]</span> <span class="token punctuation">..</span>.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token parameter variable">-c</span> <span class="token operator">&lt;</span>file<span class="token operator">&gt;</span>   <span class="token comment"># 指定cache文件(default: /etc/blkid.tab, /dev/null = none)</span>
<span class="token parameter variable">-d</span>          <span class="token comment"># don&#39;t encode non-printing characters</span>
<span class="token parameter variable">-h</span>          <span class="token comment"># 显示帮助信息</span>
<span class="token parameter variable">-g</span>          <span class="token comment"># garbage collect the blkid cache</span>
<span class="token parameter variable">-o</span> <span class="token operator">&lt;</span>format<span class="token operator">&gt;</span> <span class="token comment"># 指定输出格式</span>
<span class="token parameter variable">-k</span>          <span class="token comment"># list all known filesystems/RAIDs and exit</span>
<span class="token parameter variable">-s</span> <span class="token operator">&lt;</span>tag<span class="token operator">&gt;</span>    <span class="token comment"># 显示指定信息，默认显示所有信息</span>
<span class="token parameter variable">-t</span> <span class="token operator">&lt;</span>token<span class="token operator">&gt;</span>  <span class="token comment"># find device with a specific token (NAME=value pair)</span>
<span class="token parameter variable">-l</span>          <span class="token comment"># look up only first device with token specified by -t</span>
<span class="token parameter variable">-L</span> <span class="token operator">&lt;</span>label<span class="token operator">&gt;</span>  <span class="token comment"># convert LABEL to device name</span>
<span class="token parameter variable">-U</span> <span class="token operator">&lt;</span>uuid<span class="token operator">&gt;</span>   <span class="token comment"># convert UUID to device name</span>
<span class="token parameter variable">-v</span>          <span class="token comment"># 显示版本信息</span>
<span class="token parameter variable">-w</span> <span class="token operator">&lt;</span>file<span class="token operator">&gt;</span>   <span class="token comment"># write cache to different file (/dev/null = no write)</span>
<span class="token operator">&lt;</span>dev<span class="token operator">&gt;</span>       <span class="token comment"># specify device(s) to probe (default: all devices)</span>
Low-level probing options:
<span class="token parameter variable">-p</span>          <span class="token comment"># low-level superblocks probing (bypass cache)</span>
<span class="token parameter variable">-i</span>          <span class="token comment"># gather information about I/O limits</span>
<span class="token parameter variable">-S</span> <span class="token operator">&lt;</span>size<span class="token operator">&gt;</span>   <span class="token comment"># overwrite device size</span>
<span class="token parameter variable">-O</span> <span class="token operator">&lt;</span>offset<span class="token operator">&gt;</span> <span class="token comment"># probe at the given offset</span>
<span class="token parameter variable">-u</span> <span class="token operator">&lt;</span>list<span class="token operator">&gt;</span>   <span class="token comment"># filter by &quot;usage&quot; (e.g. -u filesystem,raid)</span>
<span class="token parameter variable">-n</span> <span class="token operator">&lt;</span>list<span class="token operator">&gt;</span>   <span class="token comment"># filter by filesystem type (e.g. -n vfat,ext3)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>1、列出当前系统中所有已挂载文件系统的类型：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>2、显示指定设备 UUID：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-s</span> UUID /dev/sda5
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>3、显示所有设备 UUID：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-s</span> UUID
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>4、显示指定设备 LABEL：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-s</span> LABEL /dev/sda5
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>5、显示所有设备 LABEL：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-s</span> LABEL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>6、显示所有设备文件系统：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-s</span> TYPE
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>7、显示所有设备：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-o</span> device
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>8、以列表方式查看详细信息：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> blkid <span class="token parameter variable">-o</span> list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,25),l=[p];function i(o,c){return s(),n("div",null,l)}const d=a(t,[["render",i],["__file","blkid.html.vue"]]);export{d as default};
